const tx=k=>T[lang][k];

function ui(){
 const ids={sub:'sub',badge:'badge',hero:'hero',herop:'herop',start:'start',practice:'practice',prog:'prog',ls:'lessons',qs:'questions',njTest:'njtest',route:'route',ct:'ct',sim:'sim',exam:'exam',examHelp:'examHelp',modeGeneral:'general',modeAir:'air',modeCombination:'combination',modeMixed:'mixed',mt:'mist',clear:'clear',navCourse:'navCourse',navExam:'navExam',navMist:'navMist',notice:'notice'};
 Object.entries(ids).forEach(([id,k])=>$('#'+id).textContent=tx(k));
 $('#search').placeholder=tx('search'); $('#lang').textContent=lang==='en'?'ES':'EN';
 renderList($('#search').value); renderLesson(); renderMistakes();
 if(deck.length) showQuestion(false);
}
function progress(){let p=Math.round(done.length/D.lessons.length*100);$('#pct').textContent=p+'%';$('#count').textContent=done.length+' / '+D.lessons.length;$('#bar').style.width=p+'%'}
function renderList(filter=''){$('#list').innerHTML='';D.lessons.forEach((l,i)=>{if(!l.title[lang].toLowerCase().includes(filter.toLowerCase()))return;let b=document.createElement('button');b.className='lesson w-full rounded-2xl border border-transparent p-4 text-left '+(i===li?'active':'');b.innerHTML=`<div class="flex gap-3"><span class="text-2xl">${l.icon}</span><div class="flex-1"><small class="font-bold text-blue-700">${tx('lesson')} ${i+1}</small><b class="block">${l.title[lang]}</b></div><span>${done.includes(i)?'✅':''}</span></div>`;b.onclick=()=>{li=i;renderList($('#search').value);renderLesson()};$('#list').appendChild(b)})}
function renderLesson(){let l=D.lessons[li];$('#lb').textContent=tx('lesson')+' '+(li+1);$('#title').textContent=l.title[lang];$('#body').textContent=l.body[lang];$('#done').textContent=done.includes(li)?tx('completed'):tx('mark');$('#tip').textContent=tx('tip');$('#tiptext').textContent=tx('tiptext');progress()}
$('#done').onclick=()=>{done=done.includes(li)?done.filter(x=>x!==li):[...done,li];localStorage.cdlDoneNJ=JSON.stringify(done);renderList($('#search').value);renderLesson()};
$('#prev').onclick=()=>{li=Math.max(0,li-1);renderList();renderLesson()};$('#next').onclick=()=>{li=Math.min(D.lessons.length-1,li+1);renderList();renderLesson()};$('#search').oninput=e=>renderList(e.target.value);

function setView(v){$$('.view').forEach(x=>x.classList.remove('active'));$('#'+v).classList.add('active');if(v==='quiz'&&!deck.length)startExam(mode);if(v==='mistakes')renderMistakes();scrollTo(0,0)}
$$('.nav').forEach(b=>b.onclick=()=>setView(b.dataset.v));
function markMode(){$$('.mode').forEach(b=>b.className='mode rounded-xl border px-4 py-3 font-bold');document.querySelector(`[data-mode="${mode}"]`).className='mode rounded-xl bg-blue-700 px-4 py-3 font-bold text-white'}
$$('.mode').forEach(b=>b.onclick=()=>{mode=b.dataset.mode;markMode();startExam(mode)});

function saveExamState(){if(!deck.length)return;localStorage.cdlExamStateNJ=JSON.stringify({mode,qi,score,answers:examAnswers,questionKeys:deck.map(q=>q.q.en),savedAt:new Date().toISOString()})}
function clearExamState(){localStorage.removeItem('cdlExamStateNJ')}
function restoreExam(){if(!savedExam||!savedExam.questionKeys?.length)return false;let restored=savedExam.questionKeys.map(k=>D.questions.find(q=>q.q.en===k)).filter(Boolean);if(!restored.length)return false;deck=restored;mode=savedExam.mode||'general';qi=Math.min(savedExam.qi||0,deck.length);score=savedExam.score||0;examAnswers=savedExam.answers||[];markMode();return true}
function startExam(m){mode=m;markMode();let pool;if(m==='general')pool=D.questions.filter(q=>q.cat==='general');else if(m==='air')pool=D.questions.filter(q=>q.cat==='air');else if(m==='combination')pool=D.questions.filter(q=>q.cat==='combination');else pool=[...D.questions].sort(()=>Math.random()-.5).slice(0,50);deck=[...pool].sort(()=>Math.random()-.5);deck.forEach(q=>delete q._order);qi=0;score=0;answered=false;examAnswers=[];saveExamState();showQuestion(true)}
function showQuestion(reset=true){if(qi>=deck.length)return result();if(reset)answered=false;let q=deck[qi];if(!q._order)q._order=[0,1,2,3].sort(()=>Math.random()-.5);q._opts=q._order.map(i=>q.o[lang][i]);q._answer=q._order.indexOf(q.a);let otherLang=lang==='en'?'es':'en';let translatedOpts=q._order.map(i=>q.o[otherLang][i]);$('#qcount').textContent=(qi+1)+' / '+deck.length;$('#scoreLive').textContent=tx('score')+': '+score;$('#qbar').style.width=(qi/deck.length*100)+'%';$('#qbox').innerHTML=`<h3 class="text-2xl font-black leading-snug">${q.q[lang]}</h3><button id="translationToggle" type="button" class="mt-4 inline-flex items-center gap-2 rounded-xl border border-blue-200 bg-blue-50 px-4 py-2 text-sm font-black text-blue-800 hover:bg-blue-100">${tx('showTranslation')}</button><div id="translationPanel" class="mt-4 hidden rounded-2xl border border-blue-200 bg-blue-50 p-5"><p class="text-xs font-black uppercase tracking-wider text-blue-700">${tx('translationTitle')}</p><p class="mt-2 text-lg font-black text-blue-950">${q.q[otherLang]}</p><div class="mt-4 grid gap-2">${translatedOpts.map((o,i)=>`<div class="rounded-xl border border-blue-100 bg-white/80 px-4 py-3 text-left font-semibold text-blue-950">${String.fromCharCode(65+i)}. ${o}</div>`).join('')}</div></div><div class="mt-6 grid gap-3">${q._opts.map((o,i)=>`<button data-i="${i}" class="ans rounded-2xl border p-4 text-left font-bold">${String.fromCharCode(65+i)}. ${o}</button>`).join('')}</div><div id="fb" class="mt-5"></div>`;let panel=$('#translationPanel'),toggle=$('#translationToggle');toggle.onclick=()=>{let opening=panel.classList.contains('hidden');panel.classList.toggle('hidden');toggle.textContent=opening?tx('hideTranslation'):tx('showTranslation')};$$('.ans').forEach(b=>b.onclick=()=>answer(+b.dataset.i,q))}
function answer(i,q){
  if(answered)return;
  answered=true;
  let wasCorrect=i===q._answer;
  examAnswers[qi]={question:q.q.en,selectedOriginalIndex:q._order[i],correctOriginalIndex:q.a,correct:wasCorrect};
  if(wasCorrect){score++;}else{
    let key=q.q.en;
    if(!mistakes.some(m=>m.q.en===key))mistakes.unshift(q);
    mistakes=mistakes.slice(0,90);
    localStorage.cdlMistNJ=JSON.stringify(mistakes);
  }
  saveExamState();
  $$('.ans').forEach((b,j)=>{if(j===q._answer)b.classList.add('correct');if(j===i&&i!==q._answer)b.classList.add('wrong')});
  $('#scoreLive').textContent=tx('score')+': '+score;
  $('#fb').innerHTML=`<div class="rounded-2xl p-5 ${i===q._answer?'bg-emerald-50':'bg-red-50'}"><b>${i===q._answer?tx('correct'):tx('wrong')}</b><p class="mt-2">${q.x[lang]}</p></div><button id="nq" class="mt-5 rounded-xl bg-blue-700 px-5 py-3 font-black text-white">${tx('next')}</button>`;
  $('#nq').onclick=()=>{qi++;saveExamState();showQuestion(true)};
}
function result(){let total=deck.length,p=Math.round(score/total*100);$('#qcount').textContent=p+'%';$('#scoreLive').textContent=tx('score')+': '+score+' / '+total;$('#qbar').style.width='100%';$('#qbox').innerHTML=`<div class="py-10 text-center"><div class="text-7xl">${p>=80?'🏆':'📚'}</div><h3 class="mt-4 text-5xl font-black">${p}%</h3><p class="mt-3 text-lg">${p>=80?tx('passed'):tx('failed')}</p><button id="again" class="mt-6 rounded-xl bg-blue-700 px-6 py-3 font-black text-white">${tx('again')}</button></div>`;$('#again').onclick=()=>{clearExamState();startExam(mode)}}
function renderMistakes(){$('#ml').innerHTML=mistakes.length?mistakes.map(q=>`<div class="rounded-2xl border bg-white p-5"><b>${q.q[lang]}</b><p class="mt-2 font-bold text-emerald-700">${q.o[lang][q.a]}</p><p class="mt-1 text-slate-600">${q.x[lang]}</p></div>`).join(''):`<div class="rounded-2xl bg-white p-8 text-center">${tx('empty')}</div>`}
$('#clear').onclick=()=>{mistakes=[];localStorage.cdlMistNJ='[]';renderMistakes()};
$('#lang').onclick=()=>{lang=lang==='en'?'es':'en';localStorage.cdlLang=lang;ui()};
ui();if(restoreExam()){if(qi>=deck.length)result();else showQuestion(true)}else startExam('general');window.addEventListener('beforeunload',saveExamState);